def compute_score() -> tuple[str, float]:
    """Score presence and relative font size of the title on slide 11.

    Improvements:
    - Defensive check if slide 11 exists.
    """
    from pptx import Presentation

    ppt_path = globals().get("modified_ppt_path")
    if ppt_path is None:
        return ("modified_ppt_path not provided in evaluation context.", 0.0)
    prs = Presentation(ppt_path)
    # Slide index 10 == "Slide 11" for users.
    if len(prs.slides) <= 10:
        return ("Presentation does not contain Slide 11.", 0.0)
    slide = prs.slides[10]

    title_shape = None
    objective_shape = None
    for shape in slide.shapes:
        if not getattr(shape, "has_text_frame", False):
            continue
        try:
            text = (shape.text or "").strip().lower()
        except Exception:
            continue
        if 'objective' in text and objective_shape is None:  # first occurrence
            objective_shape = shape
        # Require exact match (case-insensitive) for title
        if text == 'storm event analysis':
            title_shape = shape

    if title_shape is None:
        return ("Title 'Storm Event Analysis' not found on Slide 11.", 0.0)

    return ("Title 'Storm Event Analysis' found on Slide 11.", 1.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[10] if len(prs.slides) > 10 else None
    # Find title shape and objective shape
    title_shape = None
    objective_shape = None
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        text = shape.text.strip().lower()
        if text == 'storm event analysis':
            title_shape = shape
        elif 'objective' in text or 'objectives' in text:
            objective_shape = shape
    if title_shape is None:
        return ("Could not find the title shape on Slide 11.", 0.0)
    if objective_shape is None:
        return ("Could not find the objective text shape on Slide 11.", 0.0)
    # Check vertical position (y)
    title_top = title_shape.top
    objective_top = objective_shape.top
    if title_top < objective_top:
        return ("Title is positioned above the objective text.", 1.0)
    else:
        return ("Title is not above the objective text.", 0.0)

def compute_score() -> tuple[str, float]:
    # We allow only one added text shape on slide 11 with the target title text, and no removed slides/content.
    # Allow reasonable formatting changes, but not added/deleted slides/content elsewhere.
    extraneous = False
    # Check for added/removed slides
    if ppt_diff.added_slides:
        return (f"Slides were added: {[s.slide_number for s in ppt_diff.added_slides]}", 0.0)
    if ppt_diff.removed_slides:
        return (f"Slides were removed: {[s.slide_number for s in ppt_diff.removed_slides]}", 0.0)
    # Check for removed shapes on slide 11
    # (We cannot directly check for removed shapes, so instead, check for removed animations/transition on slide 11)
    any_removal_on_11 = False
    for anim in ppt_diff.removed_animations:
        if anim.slide_id == '11':
            any_removal_on_11 = True
    for tr in ppt_diff.removed_transitions:
        if tr.slide_id == '11':
            any_removal_on_11 = True
    if any_removal_on_11:
        return ("Animations or transitions were removed from slide 11.", 0.0)
    # Check for significant text changes (unrelated text added)
    # Use python-pptx to compare text on slide 11 between original and modified
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    orig_slide = None
    mod_slide = None
    slides_o = list(orig.slides)
    slides_m = list(mod.slides)
    if len(slides_o) < 11 or len(slides_m) < 11:
        return ("Slide 11 does not exist in one of the presentations.", 0.0)
    orig_slide = slides_o[10]
    mod_slide = slides_m[10]
    def get_texts(slide):
        return set([shape.text.strip() for shape in slide.shapes if hasattr(shape, 'text') and shape.has_text_frame])
    orig_texts = get_texts(orig_slide)
    mod_texts = get_texts(mod_slide)
    added_texts = mod_texts - orig_texts
    # Remove the expected title if present
    added_texts = {t for t in added_texts if t.lower() != 'storm event analysis'}
    if added_texts:
        return (f"Extraneous text added to slide 11: {added_texts}", 0.0)
    return ("No extraneous changes found.", 1.0)

